import React, { useState, useEffect } from 'react';
import './App.css';

function App() {
  const [produtos, setProdutos] = useState([]);

  // Aqui é onde eu  busco os dados do meu Backend (Porta 3001)
  useEffect(() => {
    fetch("http://localhost:3001/produtos")
      .then(res => res.json())
      .then(dados => setProdutos(dados))
      .catch(err => console.error("Erro ao carregar:", err));
  }, []);

  return (
   <div className="App">
    <h1 style={{textAlign: 'center'}}>🛒 Meu Supermercado</h1>
    
    {/* O container principal que segura os cards */}
    <div className="grid-produtos"> 
      {produtos.map((item) => (
        <div key={item.id} className="card"> {/* Cada card individual */}
          <img src={item.imagem_url} alt={item.produto} />
          <h3 style={{fontSize: '1rem', height: '40px'}}>{item.produto}</h3>
          <p className="preco">R$ {parseFloat(item.valor).toFixed(2)}</p>
          <small>Estoque: {item.estoque}</small>
          <button style={{marginTop: '10px', cursor: 'pointer'}}>Comprar</button>
        </div>
      ))}
    </div>
  </div>
);
}

export default App;
